var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"아까부터 눈에 거슬리는 게 있는데 말이야.","JPN":"ところで、さっきから気になっていることがあるんだが。","ENG":"Something's been bothering me for a while now.","TWN":"從剛才起，有件事我一直很在意。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"구조물 사이로 뻗어 나와있는 저것들… 나무 맞지?","JPN":"構造物の隙間から伸びているあれは……木だよな？","ENG":"But those things extending between the structures... Those are trees, right?","TWN":"那些在建築之間延伸的東西……是樹嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"식물은 맞아. 하지만 이미 말라죽었어.","JPN":"植物で間違いないだろう。もう枯死しているが。","ENG":"They're plants. But they're all withered up.","TWN":"是植物沒錯。但它已經枯萎了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"대장은 전에도 이면세계에서 이런 식물 표본을 본 적 있나?","JPN":"隊長は以前にも裏世界であんな形の植物を見たことがあるのか？","ENG":"Have you seen specimens like this in the Counterside before, Captain?","TWN":"隊長，你之前在異界見過這樣的植物標本？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"없어.","JPN":"いや、ない。","ENG":"Never.","TWN":"沒見過。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"드물게 화석이 발견되긴 하지만, 여긴 사람이 만든 시설 내부야. 화석이 생길 정도로 오래되지는 않았단 얘기지.","JPN":"まれに化石を発見することはあるが、ここは人が作った施設内だから、化石になるほど古くはないということだ。","ENG":"I've seen fossils, but this is inside a man-made facility. It's not old enough for fossils to have formed.","TWN":"異界裡不是沒有化石，但這是在人造設施內，它的年限還不足以形成。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"별로 당황하지 않는군.","JPN":"あんまり驚かないんだな。","ENG":"You seem pretty calm about this.","TWN":"你看起來倒是一直很冷靜嘛……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"애초에 이면세계라는 곳 자체가 상식에서 엇나간 장소니까.","JPN":"そもそも裏世界が常識外の場所だから。","ENG":"The Counterside itself is a place where common sense goes out the window.","TWN":"首先，異界本身就是一個不符合常理的地方。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"일일이 이해하려고 하면 머리만 아플 뿐이야.","JPN":"いちいち考えだすと、頭痛がしてくるだけだ。","ENG":"Trying to understand everything will only give you a headache.","TWN":"試圖全部理解它們只會讓你頭疼。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"하긴. 나도 저것들이 갑자기 날 공격하지만 않으면 아무래도 상관없어.","JPN":"確かにな。俺もあれがいきなり暴れ出すことさえなければ、別にどうでもいい。","ENG":"True. As long as those things don't suddenly attack me, they don't bother me.","TWN":"也對。只要這些東西不突然襲擊我們就無所謂。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"지금 설치하는 게 그 왜곡 필터라는 건가?","JPN":"今設置しているそれは、歪曲フィルターか？","ENG":"Are you installing the distortion filter right now?","TWN":"現在我們安裝的是那個扭曲濾鏡？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래, 이걸로 놈들의 감지기관을 차단할 거야. 아주 편안하게 잠들겠지.","JPN":"ああ、これで奴らの感覚器官を遮断する。ぐっすり眠っていられるだろう。","ENG":"Yeah, this will block their sensory organs. They'll be sleeping like babies.","TWN":"沒錯，這東西能遮罩侵蝕體的探測器官。它們會睡得非常香。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"최근 리퍼 인더스트리가 개발했다던 그 <color=#ffd34c>요람</color>이란 물건이군.","JPN":"最近リーパー・インダストリーが開発した<color=#ffd34c>ゆりかご</color>というやつか。","ENG":"So this is the <color=#ffd34c>cradle</color> that Reaper Industries recently developed.","TWN":"這是最近由收割者工業開發的名為<color=#ffd34c>搖籃</color>的東西。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그 자식들은 블랙네트워크에 유출된 기술을 응용한 것뿐이야.","JPN":"あの連中はブラックネットワークに流出した技術をそのまま流用しただけだ。","ENG":"All those bastards did was apply the technology that had been leaked onto the Dark Network.","TWN":"那些傢伙只是挪用了洩露到黑色網路上的技術。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"아이디어란 게 다 그런 거지. 어떻게 순전히 자기 머리로만 장사를 하겠어?","JPN":"アイデアなんて所詮そんなもんさ。自分で一から考えて商売するやつなんていない。","ENG":"That's how ideas work. How could anyone run a business based solely on their own ideas?","TWN":"我知道，這就是創意所在嘛。只靠自己研究怎麼能經營好一家企業呢？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"소리 들었어?","JPN":"聞こえたか？","ENG":"Did you hear that?","TWN":"你聽到了嗎？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"뭔 소리…?","JPN":"何がだ……？","ENG":"Hear what...?","TWN":"聽到什麼……？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"왜 갑자기 불이 켜진 거야?!","JPN":"おおっ、急にどうして明かりが！？","ENG":"Why did the light turn on by itself?","TWN":"燈怎麼突然亮了？！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"전력이 공급되면서 경보가 울렸군. 지알로 그 자식, 대체 뭘 건드린 거지?","JPN":"電力が供給されたことで警報が鳴り始めたな。ジャッロのやつ、いったい何をした？","ENG":"An alarm must've gone off as soon as it got power. What on earth did that idiot Giallo touch?","TWN":"接通電源以後警報器也響了。賈洛那個混蛋，到底碰了什麼？"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"동면체가 깨어났잖아! 얼른 튀어야 돼!","JPN":"冬眠してた奴らが目を覚ましたぞ！　はやく逃げないと！","ENG":"C.O.s are waking up! We have to get out of here!","TWN":"冬眠的侵蝕體要醒了！快離開這裡！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"불가능해. 여긴 직선 통로고, 놈들은 양쪽에서 몰려올 거야.","JPN":"無理だ。ここは直線通路で、奴らは両方から押し寄せる。","ENG":"It's impossible. This is a straight corridor, they'll come at us from both sides.","TWN":"逃不出去了。這是一條筆直的通道，它們會從兩邊包圍過來！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"제길! 그럼 어쩌잔 거야!","JPN":"ちくしょ！　じゃあどうすれば！","ENG":"Dammit! Now what?!","TWN":"該死！那該怎麼辦！"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"침착하고 날 엄호해.","JPN":"落ち着いて、私を援護して。","ENG":"Stay calm and cover me.","TWN":"保持冷靜，掩護我。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"요람만 활성화시키면 놈들도 우릴 노리지 않을 거야.","JPN":"ゆりかごさえ活性化されれば、奴らに狙われなくなる。","ENG":"They won't target us as soon as the cradle's activated.","TWN":"如果啟動搖籃，那些傢伙就不會鎖定我們了。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"그래, 한 번 해보자고.","JPN":"わかった、やるしかないな。","ENG":"All right, let's do this!","TWN":"好，試試看吧。"},"stage":{"bg":"FLOOR_FACILITY_01","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_TOUCH"},"R":null}}}]`);export{e as default};